bin='/home/ctfplayer/ctf_files/maze_public'
od=subprocess.check_output(['objdump','-d',bin],text=True)
lines=od.splitlines()
addrs=[]
for i,l in enumerate(lines):
    if '49 ff c7' in l: # inc r15
        # look back a few lines for movb c3 to [rax]
        window='\n'.join(lines[max(0,i-4):i+1])
        if 'c6 00 c3' in window:
            # find nearest preceding lea *,%rax line
            for j in range(i-1,max(-1,i-8),-1):
                if j>=0 and re.search(r'lea\s+.*,%rax',lines[j]):
                    m=re.match(r'^\s*([0-9a-f]+):',lines[j])
                    if m: addrs.append(int(m.group(1),16))
                    break
print('count',len(addrs),'unique',len(set(addrs)))
for a in sorted(set(addrs))[:10]: print(hex(a))
print('...')
for a in sorted(set(addrs))[-10:]: print(hex(a))
# print any inc r15 sites total
incs=[]
for l in lines:
    if '49 ff c7' in l:
        m=re.match(r'^\s*([0-9a-f]+):',l)
        if m: incs.append(int(m.group(1),16))
print('total inc r15 insns',len(incs))
